```class Solution {
public:
    int maximumLengthSubstring(string s) {
        int count[256] = {0}; // 256 is the number of characters in the ASCII table
        int max_length = 0;
        int start = 0;

        for (int i = 0; i < s.length(); i++) {
            int char_index = s[i] - 'a'; // convert character to ASCII value
            count[char_index]++;

            if (count[char_index] > 2) {
                count[char_index]--;
                start = i + 1;
            }

            max_length = max(max_length, i - start + 1);
        }

        return max_length;
    }
};```

